<template>
  <GuideLayout>
    <div class="ch-header">
      <span class="ch-header__num">第 9 章</span>
      <h1 class="ch-header__title">进阶技巧</h1>
      <p class="ch-header__desc">
        深入了解 FlowDesignerLayout 的 Provide/Inject 机制、ref API 访问、自定义插槽开发等高级特性。
      </p>
    </div>

    <!-- 导航目录 -->
    <nav class="ch-toc">
      <h3 class="ch-toc__title">目录</h3>
      <ul class="ch-toc__list">
        <li><a href="#provide-inject" @click.prevent="scrollToSection('provide-inject')">Provide/Inject 数据注入</a></li>
        <li><a href="#inject-keys" @click.prevent="scrollToSection('inject-keys')">注入参数详解</a></li>
        <li><a href="#slot-scope" @click.prevent="scrollToSection('slot-scope')">Slot Scope 使用模式</a></li>
        <li><a href="#best-practices" @click.prevent="scrollToSection('best-practices')">最佳实践</a></li>
      </ul>
    </nav>

    <!-- 9.1 Provide/Inject 数据注入概述 -->
    <section id="provide-inject" class="ch-section">
      <h2 class="ch-section__title">9.1 Provide/Inject 数据注入</h2>
      
      <p class="ch-text">
        FlowDesignerLayout 通过 Vue 3 的 <code>provide/inject</code> 机制向子组件提供了 <strong>8 个核心数据</strong>，
        让你可以在自定义组件中访问设计器的实例、权限配置、画布状态等信息。
      </p>

      <!-- 核心注入参数概览表 -->
      <div class="provide-overview-table">
        <table>
          <thead>
            <tr>
              <th>参数名称</th>
              <th>类型</th>
              <th>用途概述</th>
            </tr>
          </thead>
          <tbody>
            <tr>
              <td><code>designer</code></td>
              <td>ComputedRef&lt;FlowDesigner | null&gt;</td>
              <td>FlowDesigner 核心实例，提供所有核心 API</td>
            </tr>
            <tr>
              <td><code>graph</code></td>
              <td>ComputedRef&lt;Graph | null&gt;</td>
              <td>X6 Graph 实例，操作画布和单元格</td>
            </tr>
            <tr>
              <td><code>designerMode</code></td>
              <td>Ref&lt;DesignerMode&gt;</td>
              <td>当前设计器模式（design/readonly/preview）</td>
            </tr>
            <tr>
              <td><code>capabilities</code></td>
              <td>ComputedRef&lt;ModeCapabilities | null&gt;</td>
              <td>当前模式的权限配置，控制各项操作权限</td>
            </tr>
            <tr>
              <td><code>selectedCells</code></td>
              <td>Ref&lt;SelectedCell[]&gt;</td>
              <td>当前选中的单元格列表</td>
            </tr>
            <tr>
              <td><code>canvasConfig</code></td>
              <td>Ref&lt;CanvasConfig | null&gt;</td>
              <td>画布配置对象，包含网格、背景、连线等配置</td>
            </tr>
            <tr>
              <td><code>updateCanvasConfig</code></td>
              <td>Function</td>
              <td>更新画布配置的方法</td>
            </tr>
            <tr>
              <td><code>flowDesigner</code></td>
              <td>Ref&lt;FlowDesigner | undefined&gt;</td>
              <td>FlowDesigner 实例的响应式引用</td>
            </tr>
          </tbody>
        </table>
      </div>

      <div class="ch-callout ch-callout--info">
        <strong>💡 两种使用方式：</strong>
        <ul>
          <li><strong>方式一：Slot Scope</strong> - 推荐用于自定义插槽内容，数据通过 slot props 传递</li>
          <li><strong>方式二：Direct Inject</strong> - 用于内置核心组件，通过 inject() 获取数据</li>
        </ul>
      </div>
    </section>

    <!-- 9.2 注入参数详解 -->
    <section id="inject-keys" class="ch-section">
      <h2 class="ch-section__title">9.2 注入参数详解</h2>
      
      <p class="ch-text">以下是 FlowDesignerLayout 提供的 8 个注入参数及其详细说明：</p>

      <!-- 9.2.1 designer -->
      <div class="param-card">
        <div class="param-card__header">
          <h3 class="param-card__title">
            <span class="param-key">designer</span>
            <span class="param-type">ComputedRef&lt;FlowDesigner | null&gt;</span>
          </h3>
        </div>
        <div class="param-card__body">
          <p class="param-desc">
            FlowDesigner 核心实例，提供设计器的所有核心 API 方法。通过 slot props 或 inject 获取。
          </p>
          
          <div class="param-usage">
            <h4>主要方法：</h4>
            <ul>
              <li><code>getGraph()</code> - 获取 X6 Graph 实例</li>
              <li><code>getMeta()</code> / <code>setMeta()</code> - 获取/设置流程元数据</li>
              <li><code>save()</code> / <code>load()</code> - 保存/加载流程数据</li>
              <li><code>undo()</code> / <code>redo()</code> - 撤销/重做操作</li>
              <li><code>groupSelectedNodes()</code> - 将选中节点成组</li>
              <li><code>ungroupSelected()</code> - 解散选中的分组</li>
              <li><code>updateCanvasConfig()</code> - 更新画布配置</li>
              <li><code>setMode()</code> - 切换设计器模式</li>
              <li><code>zoom()</code> / <code>zoomTo()</code> - 缩放画布</li>
              <li><code>export()</code> - 导出流程（JSON/PNG/SVG）</li>
            </ul>
          </div>

          <div class="ch-code-block">
            <div class="code-header">使用示例：通过 Slot Scope 使用</div>
            <pre><code><span class="code-tag">&lt;template&gt;</span>
  <span class="code-tag">&lt;FlowDesignerLayout</span> <span class="code-attr">v-model:mode</span>=<span class="code-string">"mode"</span><span class="code-tag">&gt;</span>
    <span class="code-tag">&lt;template</span> <span class="code-attr">#toolbar</span>=<span class="code-string">"{ designer }"</span><span class="code-tag">&gt;</span>
      <span class="code-tag">&lt;a-button</span> <span class="code-attr">@click</span>=<span class="code-string">"handleSave(designer)"</span><span class="code-tag">&gt;</span>
        保存
      <span class="code-tag">&lt;/a-button&gt;</span>
      <span class="code-tag">&lt;a-button</span> <span class="code-attr">@click</span>=<span class="code-string">"designer?.undo()"</span><span class="code-tag">&gt;</span>
        撤销
      <span class="code-tag">&lt;/a-button&gt;</span>
    <span class="code-tag">&lt;/template&gt;</span>
  <span class="code-tag">&lt;/FlowDesignerLayout&gt;</span>
<span class="code-tag">&lt;/template&gt;</span>

<span class="code-tag">&lt;script</span> <span class="code-attr">setup</span> <span class="code-attr">lang</span>=<span class="code-string">"ts"</span><span class="code-tag">&gt;</span>
<span class="code-keyword">import</span> type { FlowDesigner } from <span class="code-string">'@/components/FlowDesigner'</span>

<span class="code-keyword">function</span> <span class="code-function">handleSave</span>(designer: FlowDesigner | <span class="code-keyword">null</span>) {
  <span class="code-keyword">if</span> (!designer) <span class="code-keyword">return</span>
  designer.save()
}
<span class="code-tag">&lt;/script&gt;</span></code></pre>
          </div>

          <div class="ch-code-block">
            <div class="code-header">使用示例：在自定义组件中通过 inject 使用</div>
            <pre><code><span class="code-comment">// CustomToolbar.vue</span>
<span class="code-tag">&lt;script</span> <span class="code-attr">setup</span> <span class="code-attr">lang</span>=<span class="code-string">"ts"</span><span class="code-tag">&gt;</span>
<span class="code-keyword">import</span> { inject, computed } from <span class="code-string">'vue'</span>
<span class="code-keyword">import</span> type { ComputedRef } from <span class="code-string">'vue'</span>
<span class="code-keyword">import</span> type { FlowDesigner } from <span class="code-string">'@/components/FlowDesigner'</span>

<span class="code-keyword">const</span> designer = inject&lt;ComputedRef&lt;FlowDesigner | <span class="code-keyword">null</span>&gt;&gt;(<span class="code-string">'designer'</span>)

<span class="code-keyword">const</span> <span class="code-function">handleGroup</span> = () =&gt; {
  <span class="code-keyword">if</span> (!designer?.value) <span class="code-keyword">return</span>
  designer.value.groupSelectedNodes()
}

<span class="code-keyword">const</span> <span class="code-function">handleExport</span> = () =&gt; {
  <span class="code-keyword">if</span> (!designer?.value) <span class="code-keyword">return</span>
  <span class="code-keyword">const</span> data = designer.value.export(<span class="code-string">'json'</span>)
  console.log(<span class="code-string">'导出数据：'</span>, data)
}
<span class="code-tag">&lt;/script&gt;</span></code></pre>
          </div>
        </div>
      </div>

      <!-- 9.2.2 graph -->
      <div class="param-card">
        <div class="param-card__header">
          <h3 class="param-card__title">
            <span class="param-key">graph</span>
            <span class="param-type">ComputedRef&lt;Graph | null&gt;</span>
          </h3>
        </div>
        <div class="param-card__body">
          <p class="param-desc">
            X6 Graph 实例，可直接调用 AntV X6 的所有 API 进行底层操作。
          </p>
          
          <div class="param-usage">
            <h4>常用方法：</h4>
            <ul>
              <li><code>getCellById(id)</code> - 根据 ID 获取节点/边</li>
              <li><code>getNodes()</code> - 获取所有节点</li>
              <li><code>getEdges()</code> - 获取所有边</li>
              <li><code>addNode()</code> - 添加节点</li>
              <li><code>removeCell()</code> - 删除单元格</li>
              <li><code>zoom()</code> - 缩放画布</li>
            </ul>
          </div>

          <div class="ch-code-block">
            <div class="code-header">使用示例：通过 Slot Scope 使用</div>
            <pre><code><span class="code-tag">&lt;template</span> <span class="code-attr">#properties</span>=<span class="code-string">"{ graph, selectedCells }"</span><span class="code-tag">&gt;</span>
  <span class="code-tag">&lt;div</span> <span class="code-attr">v-if</span>=<span class="code-string">"selectedCells[0]"</span><span class="code-tag">&gt;</span>
    <span class="code-tag">&lt;a-button</span> <span class="code-attr">@click</span>=<span class="code-string">"handleGetNeighbors(graph, selectedCells[0].id)"</span><span class="code-tag">&gt;</span>
      查看邻居节点
    <span class="code-tag">&lt;/a-button&gt;</span>
  <span class="code-tag">&lt;/div&gt;</span>
<span class="code-tag">&lt;/template&gt;</span>

<span class="code-tag">&lt;script</span> <span class="code-attr">setup</span> <span class="code-attr">lang</span>=<span class="code-string">"ts"</span><span class="code-tag">&gt;</span>
<span class="code-keyword">import</span> type { Graph } from <span class="code-string">'@antv/x6'</span>

<span class="code-keyword">function</span> <span class="code-function">handleGetNeighbors</span>(graph: Graph | <span class="code-keyword">null</span>, nodeId: string) {
  <span class="code-keyword">if</span> (!graph) <span class="code-keyword">return</span>
  <span class="code-keyword">const</span> node = graph.getCellById(nodeId)
  <span class="code-keyword">if</span> (!node) <span class="code-keyword">return</span>
  <span class="code-keyword">const</span> neighbors = graph.getNeighbors(node)
  console.log(<span class="code-string">'邻居节点：'</span>, neighbors)
}
<span class="code-tag">&lt;/script&gt;</span></code></pre>
          </div>

          <div class="ch-code-block">
            <div class="code-header">使用示例：在自定义组件中通过 inject 使用</div>
            <pre><code><span class="code-comment">// CustomNodeInfo.vue</span>
<span class="code-tag">&lt;template&gt;</span>
  <span class="code-tag">&lt;div</span> <span class="code-attr">class</span>=<span class="code-string">"node-info"</span><span class="code-tag">&gt;</span>
    <span class="code-tag">&lt;h4&gt;</span>画布信息<span class="code-tag">&lt;/h4&gt;</span>
    <span class="code-tag">&lt;p&gt;</span>节点数量: {{ nodeCount }}<span class="code-tag">&lt;/p&gt;</span>
    <span class="code-tag">&lt;p&gt;</span>连线数量: {{ edgeCount }}<span class="code-tag">&lt;/p&gt;</span>
    <span class="code-tag">&lt;a-button</span> <span class="code-attr">@click</span>=<span class="code-string">"handleZoomIn"</span><span class="code-tag">&gt;</span>放大<span class="code-tag">&lt;/a-button&gt;</span>
    <span class="code-tag">&lt;a-button</span> <span class="code-attr">@click</span>=<span class="code-string">"handleZoomOut"</span><span class="code-tag">&gt;</span>缩小<span class="code-tag">&lt;/a-button&gt;</span>
  <span class="code-tag">&lt;/div&gt;</span>
<span class="code-tag">&lt;/template&gt;</span>

<span class="code-tag">&lt;script</span> <span class="code-attr">setup</span> <span class="code-attr">lang</span>=<span class="code-string">"ts"</span><span class="code-tag">&gt;</span>
<span class="code-keyword">import</span> { inject, computed } from <span class="code-string">'vue'</span>
<span class="code-keyword">import</span> type { ComputedRef } from <span class="code-string">'vue'</span>
<span class="code-keyword">import</span> type { Graph } from <span class="code-string">'@antv/x6'</span>

<span class="code-comment">// 注入 graph 实例</span>
<span class="code-keyword">const</span> graph = inject&lt;ComputedRef&lt;Graph | <span class="code-keyword">null</span>&gt;&gt;(<span class="code-string">'graph'</span>)

<span class="code-comment">// 计算节点和边的数量</span>
<span class="code-keyword">const</span> nodeCount = computed(() =&gt; {
  <span class="code-keyword">return</span> graph?.value?.getNodes().length ?? <span class="code-number">0</span>
})

<span class="code-keyword">const</span> edgeCount = computed(() =&gt; {
  <span class="code-keyword">return</span> graph?.value?.getEdges().length ?? <span class="code-number">0</span>
})

<span class="code-comment">// 放大画布</span>
<span class="code-keyword">const</span> <span class="code-function">handleZoomIn</span> = () =&gt; {
  <span class="code-keyword">if</span> (!graph?.value) <span class="code-keyword">return</span>
  <span class="code-keyword">const</span> currentZoom = graph.value.zoom()
  graph.value.zoom(currentZoom + <span class="code-number">0.1</span>)
}

<span class="code-comment">// 缩小画布</span>
<span class="code-keyword">const</span> <span class="code-function">handleZoomOut</span> = () =&gt; {
  <span class="code-keyword">if</span> (!graph?.value) <span class="code-keyword">return</span>
  <span class="code-keyword">const</span> currentZoom = graph.value.zoom()
  graph.value.zoom(currentZoom - <span class="code-number">0.1</span>)
}
<span class="code-tag">&lt;/script&gt;</span></code></pre>
          </div>
        </div>
      </div>

      <!-- 9.2.3 designerMode -->
      <div class="param-card">
        <div class="param-card__header">
          <h3 class="param-card__title">
            <span class="param-key">designerMode</span>
            <span class="param-type">Ref&lt;DesignerMode&gt;</span>
          </h3>
        </div>
        <div class="param-card__body">
          <p class="param-desc">
            当前设计器模式，可能的值：<code>'design'</code> | <code>'readonly'</code> | <code>'preview'</code> | 自定义模式。
          </p>

          <div class="ch-code-block">
            <div class="code-header">使用示例</div>
            <pre><code><span class="code-tag">&lt;template</span> <span class="code-attr">#properties</span>=<span class="code-string">"{ designerMode }"</span><span class="code-tag">&gt;</span>
  <span class="code-tag">&lt;a-form</span> <span class="code-attr">:disabled</span>=<span class="code-string">"designerMode !== 'design'"</span><span class="code-tag">&gt;</span>
    <span class="code-tag">&lt;a-form-item</span> <span class="code-attr">label</span>=<span class="code-string">"节点名称"</span><span class="code-tag">&gt;</span>
      <span class="code-tag">&lt;a-input</span> <span class="code-attr">v-model</span>=<span class="code-string">"nodeName"</span> <span class="code-tag">/&gt;</span>
    <span class="code-tag">&lt;/a-form-item&gt;</span>
  <span class="code-tag">&lt;/a-form&gt;</span>
  
  <span class="code-tag">&lt;div</span> <span class="code-attr">v-if</span>=<span class="code-string">"designerMode === 'readonly'"</span> <span class="code-attr">class</span>=<span class="code-string">"readonly-tip"</span><span class="code-tag">&gt;</span>
    当前为只读模式，无法编辑
  <span class="code-tag">&lt;/div&gt;</span>
<span class="code-tag">&lt;/template&gt;</span></code></pre>
          </div>
        </div>
      </div>

      <!-- 9.2.4 capabilities -->
      <div class="param-card">
        <div class="param-card__header">
          <h3 class="param-card__title">
            <span class="param-key">capabilities</span>
            <span class="param-type">ComputedRef&lt;ModeCapabilities&gt;</span>
          </h3>
        </div>
        <div class="param-card__body">
          <p class="param-desc">
            当前模式的权限配置对象，包含 38 个细粒度权限字段。
          </p>
          
          <div class="param-usage">
            <h4>常用权限字段：</h4>
            <ul>
              <li><code>canDrag</code> - 是否可拖拽节点</li>
              <li><code>canDelete</code> - 是否可删除</li>
              <li><code>canCopy</code> / <code>canPaste</code> - 复制粘贴权限</li>
              <li><code>canUndo</code> / <code>canRedo</code> - 撤销重做权限</li>
              <li><code>showToolbar</code> / <code>showNodePalette</code> - UI 显示权限</li>
              <li>更多权限请参考第 5 章权限系统</li>
            </ul>
          </div>

          <div class="ch-code-block">
            <div class="code-header">使用示例</div>
            <pre><code><span class="code-tag">&lt;template</span> <span class="code-attr">#toolbar</span>=<span class="code-string">"{ capabilities, graph, selectedCells }"</span><span class="code-tag">&gt;</span>
  <span class="code-tag">&lt;a-space&gt;</span>
    <span class="code-tag">&lt;a-button</span>
      <span class="code-attr">:disabled</span>=<span class="code-string">"!capabilities.canDelete || selectedCells.length === 0"</span>
      <span class="code-attr">@click</span>=<span class="code-string">"handleDelete(graph, selectedCells)"</span>
    <span class="code-tag">&gt;</span>
      删除
    <span class="code-tag">&lt;/a-button&gt;</span>
    
    <span class="code-tag">&lt;a-button</span>
      <span class="code-attr">:disabled</span>=<span class="code-string">"!capabilities.canGroup"</span>
      <span class="code-attr">@click</span>=<span class="code-string">"designer?.groupSelectedNodes()"</span>
    <span class="code-tag">&gt;</span>
      成组
    <span class="code-tag">&lt;/a-button&gt;</span>
    
    <span class="code-tag">&lt;a-button</span>
      <span class="code-attr">:disabled</span>=<span class="code-string">"!capabilities.canUndo"</span>
      <span class="code-attr">@click</span>=<span class="code-string">"designer?.undo()"</span>
    <span class="code-tag">&gt;</span>
      撤销
    <span class="code-tag">&lt;/a-button&gt;</span>
  <span class="code-tag">&lt;/a-space&gt;</span>
<span class="code-tag">&lt;/template&gt;</span>

<span class="code-tag">&lt;script</span> <span class="code-attr">setup</span> <span class="code-attr">lang</span>=<span class="code-string">"ts"</span><span class="code-tag">&gt;</span>
<span class="code-keyword">function</span> <span class="code-function">handleDelete</span>(graph, selectedCells) {
  <span class="code-keyword">if</span> (!graph || selectedCells.length === <span class="code-number">0</span>) <span class="code-keyword">return</span>
  selectedCells.forEach(<span class="code-function">cell</span> =&gt; {
    <span class="code-keyword">const</span> cellInstance = graph.getCellById(cell.id)
    <span class="code-keyword">if</span> (cellInstance) graph.removeCell(cellInstance)
  })
}
<span class="code-tag">&lt;/script&gt;</span></code></pre>
          </div>
        </div>
      </div>

      <!-- 9.2.5 selectedCells -->
      <div class="param-card">
        <div class="param-card__header">
          <h3 class="param-card__title">
            <span class="param-key">selectedCells</span>
            <span class="param-type">Ref&lt;SelectedCell[]&gt;</span>
          </h3>
        </div>
        <div class="param-card__body">
          <p class="param-desc">
            当前选中的单元格列表，每个元素包含 <code>id</code>、<code>type</code>（'node' | 'edge'）、<code>shape</code>。
          </p>

          <div class="ch-code-block">
            <div class="code-header">使用示例</div>
            <pre v-pre><code><span class="code-tag">&lt;template</span> <span class="code-attr">#properties</span>=<span class="code-string">"{ selectedCells, graph }"</span><span class="code-tag">&gt;</span>
  <span class="code-tag">&lt;div</span> <span class="code-attr">v-if</span>=<span class="code-string">"selectedCells.length === 0"</span><span class="code-tag">&gt;</span>
    未选中任何元素
  <span class="code-tag">&lt;/div&gt;</span>
  
  <span class="code-tag">&lt;div</span> <span class="code-attr">v-else-if</span>=<span class="code-string">"selectedCells.length === 1"</span><span class="code-tag">&gt;</span>
    <span class="code-tag">&lt;h4&gt;</span>{{ selectedCells[0].type === 'node' ? '节点' : '连线' }}属性<span class="code-tag">&lt;/h4&gt;</span>
    <span class="code-tag">&lt;p&gt;</span>ID: {{ selectedCells[0].id }}<span class="code-tag">&lt;/p&gt;</span>
    <span class="code-tag">&lt;p&gt;</span>类型: {{ selectedCells[0].shape }}<span class="code-tag">&lt;/p&gt;</span>
  <span class="code-tag">&lt;/div&gt;</span>
  
  <span class="code-tag">&lt;div</span> <span class="code-attr">v-else</span><span class="code-tag">&gt;</span>
    已选中 {{ selectedCells.length }} 个元素
  <span class="code-tag">&lt;/div&gt;</span>
<span class="code-tag">&lt;/template&gt;</span></code></pre>
          </div>
        </div>
      </div>

      <!-- 9.2.6 canvasConfig -->
      <div class="param-card">
        <div class="param-card__header">
          <h3 class="param-card__title">
            <span class="param-key">canvasConfig</span>
            <span class="param-type">Ref&lt;CanvasConfig | null&gt;</span>
          </h3>
        </div>
        <div class="param-card__body">
          <p class="param-desc">
