            <tr>
              <td><code>#properties</code></td>
              <td>designer, graph, selectedCells, capabilities, currentMode</td>
              <td>自定义属性面板</td>
            </tr>
            <tr>
              <td><code>#node-tooltip</code></td>
              <td>node, data, designer, graph</td>
