        </table>
      </div>

      <div class="ch-callout ch-callout--success">
        <strong>✅ 推荐模式：</strong>
        <ul>
          <li><strong>外部自定义组件</strong> → 使用 Slot Scope（通过 slot props 获取数据）</li>
          <li><strong>内部核心组件</strong> → 使用 Direct Inject（通过 inject() 获取数据）</li>
        </ul>
      </div>
    </section>

    <!-- 9.4 最佳实践 -->
    <section id="best-practices" class="ch-section">
      <h2 class="ch-section__title">9.4 最佳实践</h2>

      <!-- 实践 1：权限检查优先 -->
