                <pre><code><span class="code-comment">// 先检查权限再执行操作</span>
<span class="code-keyword">if</span> (capabilities.value?.canGroup) {
  designer.value?.groupSelectedNodes()
}</code></pre>
              </div>
            </div>
            
            <div class="practice-example__bad">
