<span class="code-keyword">const</span> node = graph.value?.getCellById(nodeId)
<span class="code-keyword">if</span> (node?.isNode()) {
  <span class="code-comment">// 操作节点</span>
}</code></pre>
              </div>
            </div>
            
            <div class="practice-example__bad">
              <div class="practice-example__label">❌ 错误</div>
              <div class="ch-code-block">
                <pre><code><span class="code-comment">// 不判断直接访问，可能报错</span>
<span class="code-keyword">const</span> node = graph.value.getCellById(nodeId)</code></pre>
              </div>
            </div>
          </div>
        </div>
      </div>

      <!-- 实践 3：响应式追踪 -->
      <div class="practice-card">
        <h3 class="practice-card__title">⚡ 实践 3：响应式追踪</h3>
        <div class="practice-card__content">
          <div class="practice-example">
            <div class="practice-example__good">
              <div class="practice-example__label">✅ 正确</div>
              <div class="ch-code-block">
                <pre><code><span class="code-comment">// 使用 computed 追踪变化</span>
<span class="code-keyword">const</span> selectedNode = <span class="code-function">computed</span>(() => {
  <span class="code-keyword">if</span> (!selectedCells.value[<span class="code-number">0</span>]) <span class="code-keyword">return</span> <span class="code-keyword">null</span>
  <span class="code-keyword">return</span> graph.value?.getCellById(selectedCells.value[<span class="code-number">0</span>].id)
})</code></pre>
              </div>
            </div>
            
            <div class="practice-example__bad">
