<span class="code-tag">&lt;FlowDesignerLayout&gt;</span>
  <span class="code-tag">&lt;template</span> <span class="code-attr">#toolbar</span>=<span class="code-string">"{ onCopy, capabilities }"</span><span class="code-tag">&gt;</span>
